#include <string>
#include <unordered_map>
std::string minWindow(std::string s, std::string t)
{
    if (t.size() > s.size())
        return "";
    if (s.size() == 1 && t.size() == 1)
    {
        if (s == t)
            return s;
        else
            return "";
    }
    bool ans_found = false;
    std::unordered_map<char, int> need, have;
    for (auto c : t)
        need[c]++;
    int need_count = need.size();
    int have_count = 0;
    std::string ans;
    std::pair<int, int> ans_bound;

    int left = 0;
    for (int right = left; right < s.size(); right++)
    {
        char ch = s[right];
        if (need.count(ch))
        {
            have[ch]++;
            if (have[ch] == need[ch])
                have_count++;
        }
        if (have_count == need_count)
        {
            if (!ans_found)
            {
                ans_found = true;
                ans_bound = {left, right};
            }
            else if ((right - left + 1) < (ans_bound.second - ans_bound.first + 1))
                ans_bound = {left, right};

            // std::string temp = s.substr(left, right - left + 1);
            // if (!ans.size())
            //     ans = temp;
            // else if (temp.size() < ans.size())
            //     ans = temp;
        }

        while (have_count == need_count)
        {
            char ch = s[left];
            if (need.count(ch))
            {
                have[ch]--;
                if (have[ch] < need[ch])
                    have_count--;
            }
            left++;

            if (have_count == need_count)
            {
                if ((right - left + 1) < (ans_bound.second - ans_bound.first + 1))
                    ans_bound = {left, right};

                // std::string temp = s.substr(left, right - left + 1);
                // if (!ans.size())
                //     ans = temp;
                // else if (temp.size() < ans.size())
                //     ans = temp;
            }
        }
    }
    if (ans_found)
        return s.substr(ans_bound.first, ans_bound.second - ans_bound.first + 1);
    else
        return "";
}
std::string minWindowNotworking(std::string s, std::string t)
{
    std::unordered_map<char, int> target;
    for (auto c : t)
        target[c]++;

    std::unordered_map<char, int> window;

    int left = 0;
    int right = 0;
    int match_count = 0;
    std::string ans;

    // find the first window
    while (!target.count(s[left]))
        left++;
    match_count++;
    ;
    window[s[left]]++;
    right = left + 1;
    while (right < s.size())
    {
        if (target.count(s[right]))
        {
            if (window[s[right]] < target[s[right]])
                match_count++;
            window[s[right]]++;
        }
        if (match_count == t.size())
        {
            ans = s.substr(left, right - left + 1);
            break;
        }
        right++;
    }
    if (match_count < t.size())
        return "";

    while (right < s.size())
    {
        // keep shrinking the left until the next char is found
        window[s[left]]--;
        match_count--;
        left++;
        while (!target.count(s[left]))
            left++;

        // right++;
        while (right < s.size())
        {
            if (target.count(s[right]))
            {
                if (window[s[right]] < target[s[right]])
                    match_count++;
                window[s[right]]++;
            }
            if (match_count == t.size())
            {
                std::string temp = s.substr(left, right - left + 1);
                if (temp.size() < ans.size())
                    ans = temp;
                break;
            }
            right++;
        }
    }

    return ans;
}
